        // Stock Market Data via Yahoo Finance API (free, no key)
        // Fetches real-time and historical OHLCV data for stocks, ETFs, indices

        $timeout = min(30, max(5, $timeout ?? 15));
        $symbol = strtoupper(trim($symbol ?? ''));
        $range = $range ?? '1d';
        $interval = $interval ?? '';
        $includePreviousClose = $include_previous_close ?? true;

        if (empty($symbol)) {
