        // Validate range
        $validRanges = ['1d', '5d', '1mo', '3mo', '6mo', '1y', '2y', '5y', '10y', 'ytd', 'max'];
        if (!in_array($range, $validRanges)) {
            return ['success' => false, 'error' => "Invalid range '$range'. Must be: " . implode(', ', $validRanges), 'symbol' => $symbol];
        }

        try {
            // Build URL
            $url = 'https://query1.finance.yahoo.com/v8/finance/chart/' . urlencode($symbol);

            $params = ['range' => $range];
            if (!empty($interval)) {
