            if ($quote['market_price'] !== null && $quote['previous_close'] !== null && $quote['previous_close'] > 0) {
                $change = $quote['market_price'] - $quote['previous_close'];
                $changePercent = ($change / $quote['previous_close']) * 100;
                $quote['change'] = round($change, 2);
                $quote['change_percent'] = round($changePercent, 2);
            }

            // Build historical data
            $historical = [];
            $count = min(count($timestamps), count($quotes['open'] ?? []));

            for ($i = 0; $i < $count; $i++) {
                $ts = $timestamps[$i];
